// Checkout.js
import React, { useState, useContext } from "react";
import { useNavigate } from "react-router-dom";
import { CartContext } from "../context/CartContext";

const Checkout = () => {
  const navigate = useNavigate();
  const { cartItems, getTotal, clearCart } = useContext(CartContext);
  const [formData, setFormData] = useState({
    name: "",
    address: "",
    mobile: "",
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!formData.name || !formData.address || !formData.mobile) {
      alert("Please fill all fields before placing your order!");
      return;
    }

    const orderData = {
      id: Date.now(),
      ...formData,
      total: getTotal(),
      items: cartItems,
      date: new Date().toLocaleString(),
      status: "Placed",
    };

    const existingOrders = JSON.parse(localStorage.getItem("orders")) || [];
    const updatedOrders = [...existingOrders, orderData];

    localStorage.setItem("orders", JSON.stringify(updatedOrders));

    clearCart();
    navigate("/orders");
  };

  return (
    <div className="checkout-container">
      <h2>Checkout</h2>
      <form onSubmit={handleSubmit}>
        <input type="text" name="name" placeholder="Full Name" onChange={handleChange} />
        <input type="text" name="address" placeholder="Address" onChange={handleChange} />
        <input type="text" name="mobile" placeholder="Mobile No." onChange={handleChange} />
        <button type="submit">Place Order</button>
      </form>
    </div>
  );
};

export default Checkout;
